def is_balanced(s):
    stack = []
    matching = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != matching[char]:
                return False
            stack.pop()
    return len(stack) == 0

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_simple_parens(self):
        self.assertTrue(is_balanced('()'))

    def test_all_bracket_types(self):
        self.assertTrue(is_balanced('()[]{}'))

    def test_mismatched(self):
        self.assertFalse(is_balanced('(]'))

    def test_hidden_empty_string(self):
        self.assertTrue(is_balanced(''))

    def test_hidden_nested_correct(self):
        self.assertTrue(is_balanced('([{}])'))

    def test_hidden_interleaved_wrong(self):
        self.assertFalse(is_balanced('({[)]}'))

    def test_hidden_unclosed_openers(self):
        self.assertFalse(is_balanced('((('))

    def test_hidden_only_closers(self):
        self.assertFalse(is_balanced(')))'))

    def test_hidden_non_bracket_chars(self):
        self.assertTrue(is_balanced('a(b[c]d)e'))

    def test_hidden_single_opener(self):
        self.assertFalse(is_balanced('{'))

    def test_hidden_no_brackets(self):
        self.assertTrue(is_balanced('hello world'))

    def test_hidden_deep_nesting(self):
        self.assertTrue(is_balanced('((([[{{}}]])))'))

if __name__ == '__main__':
    unittest.main()
